            new CyberwareDef { Name = "Киберглаз", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 0, HumanityLoss = "2d6 (7)", IsFoundation = true, Description = "Все нижеописанные опции устанавливаются в искусственный глаз, заменяющий органический.\r\nКаждый киберглаз имеет 3 слота опций для киберглаза. Некоторые опции должны быть\r\nсопряжёнными, чтобы работать корректно (покупаются дважды и устанавливаются в два\r\nразных киберглаза персонажа, ПЧ рассчитывается отдельно за каждую покупку)." },
            new CyberwareDef { Name = "Антиослепление", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 1, IsPaired = true, HumanityLoss = "1d6/2 (2)", Requires = "Киберглаз", Description = "Пользователь иммунен к слепоте и другим эффектам, вызванным опасными\r\nвспышками света, например от светошумовой гранаты. Требует два сопряжённых киберглаза." },
            new CyberwareDef { Name = "Виртуальность", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 1, IsPaired = true, HumanityLoss = "1d6/2 (2)", Requires = "Киберглаз", Description = "Проецирует изображение киберпространства поверх реального мира.\r\nБольше не забудешь свои очки виртуальности. Требует два сопряжённых киберглаза." },
            new CyberwareDef { Name = "Детектор радиации", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберглаз", Description = "Показания радиации в радиусе 100 м отображаются в поле\r\nзрения пользователя синим свечением над источником. Требует киберглаз." },
            new CyberwareDef { Name = "Дротикомёт", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 3, HumanityLoss = "1d6/2 (2)", Requires = "Киберглаз", Description = "Однозарядное экзотическое оружие дротикомёт,\r\nскрытое в глазу. Требует киберглаз и занимает 3 слота опций." },
            new CyberwareDef { Name = "Микровидео", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 2, HumanityLoss = "1d6/2 (2)", Requires = "Киберглаз", Description = "Камера в глазу записывает видео и аудио на стандартную щепку\r\nпамяти или связанный агент. Требует киберглаз и занимает 2 слота опций." },
            new CyberwareDef { Name = "Микрооптика", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Киберглаз", Description = "Микроскоп с увеличением до ×400. Требует киберглаз." },
            new CyberwareDef { Name = "ПНВ/ИК/УФ", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 2, IsPaired = true, HumanityLoss = "1d6 (3)", Requires = "Киберглаз", Description = "Снижает штрафы от темноты и других нематериальных помех (дым, туман\r\nи т.п.) до 0. Пользователь различает горячую плоть и холодный металл, но не видит сквозь\r\nукрытия. Требует два сопряженных киберглаза, занимает по 2 слота в каждом киберглазе." },
            new CyberwareDef { Name = "Прицельный модуль", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберглаз", Description = "Пользователь получает +1 к проверке при выполнении прицельной\r\nатаки. Повторные установки не дают дополнительного эффекта. Требует киберглаз." },
            new CyberwareDef { Name = "Улучшение изображения", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 1, IsPaired = true, HumanityLoss = "1d6 (3)", Requires = "Киберглаз", Description = "+2 к восприятию, чтению по губам и скрыть/обнаружить объект. Требует\r\nдва сопряжённых киберглаза. Повторные установки не дают дополнительного эффекта.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Внимательность", Value = 2, ModType = "Visual" }, new SkillModifierDef { SkillName = "Чтение по губам", Value = 2}, new SkillModifierDef { SkillName = "Скрытие/раскрытие объекта", Value = 2} } },
            new CyberwareDef { Name = "Сдвиг цвета", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Киберглаз", Description = "Косметическое улучшение, позволяющее менять цвет и узор глаз\r\nнеограниченное число раз действием. Глаз может быть чувствительным к температуре\r\nили реагировать на гормональные изменения. Требует киберглаз." },
            new CyberwareDef { Name = "Телеоптика", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберглаз", Description = "Пользователь видит детали на расстоянии до 800м. При атаке цели\r\nна дистанции 51м и дальше одиночным выстрелом или прицельным выстрелом\r\nможно добавить +1 к проверке. Повторные установки не дают эффекта. Не суммируется\r\nс приспособлением оружия снайперский прицел. Требует киберглаз." },
            new CyberwareDef { Name = "Хирон", Category = "ЛЕВЫЙ КИБЕРГЛАЗ (CYBEROPTIC L)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Киберглаз", Description = "Проецирует подэкран в поле зрения." },

            // ================== КИБЕРАУДИО ==================
            new CyberwareDef { Name = "Набор кибераудио", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 0, HumanityLoss = "2d6 (7)", IsFoundation = true, Description = "Набор кибераудио устанавливается скрытно во внутреннюю часть черепа. Система имеет 3\r\nслота для опций кибераудио. Пользователь может иметь только один установленный набор." },
            new CyberwareDef { Name = "Анализатор голосового напряжения", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Набор кибераудио", Description = "Пользователь добавляет +2 к своим навыкам проницательность\r\nи допрос. Пользователь может активировать специальную функцию детектора лжи на одну\r\nминуту с помощью действия, в течение которой рефери тайно совершает все проверки\r\nпроницательности и допроса твоего персонажа, подавая звуковой сигнал всякий раз,\r\nкогда обнаруживает ложь или когда пожелает после проваленного броска. Остерегайтесь\r\nложноположительных и ложноотрицательных результатов. Требует набор кибераудио.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Проницательность", Value = 2 }, new SkillModifierDef { SkillName = "Допрос", Value = 2 } } },
            new CyberwareDef { Name = "Внутренний агент", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Набор кибераудио", Description = "Полнофункциональный агент (см. раздел снаряжения стр. 358),\r\nуправляемый исключительно голосовыми командами. Изображения описываются\r\nголосом, но вывод может быть связан с киберглазом с хироном или ближайшим\r\nэкраном, если требуется визуальный вывод. Щепку памяти имплантированного агента\r\nнельзя извлечь без хирургического вмешательства. Требует набор кибераудио." },
            new CyberwareDef { Name = "Демпфер", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Набор кибераудио", Description = "Автоматическая компенсация шума. Пользователь\r\nневосприимчив к глухоте или другим эффектам, вызванным опасно громкими\r\nзвуками, например, от светошумовой гранаты. Требует набор кибераудио." },
            new CyberwareDef { Name = "Детектор жучков", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Набор кибераудио", Description = "Подает звуковой сигнал, когда пользователь находится в пределах 2 м\r\nот прослушки, жучка или другого подслушивающего устройства. Требует набор кибераудио." },
            new CyberwareDef { Name = "Диктофон", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Набор кибераудио", Description = "Записывает звук на стандартный чип памяти\r\nили на связанный Агент. Требует набор кибераудио." },
            new CyberwareDef { Name = "Радар-детектор", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Набор кибераудио", Description = "Подает звуковой сигнал, если в пределах 100 м\r\nприсутствует активный луч радара. Требует набор кибераудио." },
            new CyberwareDef { Name = "Радиокоммуникатор", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Набор кибераудио", Description = "Пользователь может общаться по радио,\r\nрадиус действия 1.6 км. Требует набор кибераудио." },
            new CyberwareDef { Name = "Радиосканер/музыкальный плеер", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Набор кибераудио", Description = "Пользователь может использовать действие, чтобы просканировать все\r\nрадиодиапазоны в пределах 1.6 км, которые используются в данный момент, и настроиться\r\nна них. Музыкальный плеер может подключаться к ДатаПулу, чтобы слушать самые\r\nгорячие хиты, или воспроизводить музыку напрямую с щепки памяти. Для понимания\r\nзашифрованных каналов требуется Шифратор/Дешифратор. Требует набор кибераудио." },
            new CyberwareDef { Name = "Трекер", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Набор кибераудио", Description = "Может отслеживать связанный маячок на расстоянии\r\nдо 1.6 км. В комплект входит один бесплатный связанный маячок размером с кнопку.\r\nЗамена стоит 50eb. Требует набор кибераудио." },
            new CyberwareDef { Name = "Усиленный слух", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Набор кибераудио", Description = "+2 к проверкам восприятия, связанным со слухом. Не\r\nсуммируется при повторной установке. Требует набор кибераудио.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Внимательность", Value = 2, ModType = "Audio" } } },
            new CyberwareDef { Name = "Шифратор/дешифратор", Category = "КИБЕРАУДИО (CYBERAUDIO)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Набор кибераудио", Description = "Позволяет пользователю шифровать исходящие сообщения,\r\nчтобы их нельзя было понять без дешифратора, который также включен\r\nв комплект без дополнительной платы. Требует набор кибераудио." },

            // ================== ВНУТРЕННИЕ ИМПЛАНТЫ ==================
            new CyberwareDef { Name = "АудиоВокс", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "1d6 (3)", Description = "Синтезатор голоса. Пользователь добавляет +2 к навыку актерское\r\nмастерство, а также +2 к навыку игра на инструменте во время пения.\r\nПовторная установка не дает дополнительных преимуществ.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Актерское мастерство", Value = 2 }, new SkillModifierDef { SkillName = "Игра на инструментах", Value = 2 } } },
            new CyberwareDef { Name = "Вампиры", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "4d6 (14)", Description = "Клыки, вживленные в рот. Легкое холодное оружие отличного качества\r\n(урон 1d6, 2 СКОР), скрываемое без проверки. В небе рта есть отсек для яда\r\nили биотоксина (покупается отдельно, стр. 360), который наносится на клыки\r\nбез использования действия. Одной порции хватает на 30 минут. Установка включает\r\nполную переделку рта, так что ты не отравишься сам, когда ешь пиццу." },
            new CyberwareDef { Name = "Жабры", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "2d6 (7)", Description = "Позволяют дышать под водой." },
            new CyberwareDef { Name = "Искусственные мышцы и усиленные кости", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "4d6 (14)", Description = "Ты увеличиваешь характеристику ТЕЛО на 2. Это изменение влияет\r\nна твои ПЗ, Порог ранения и Спасбросок от смерти. Эффекты от не скольких\r\nустановок суммируются, но нельзя поднять ТЕЛО выше 10." },
            new CyberwareDef { Name = "Киберзмей", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "4d6 (14)", Description = "Ужасающее оружие-щупальце, вмонтированное в горло/пищевод. Считается очень\r\nтяжелым холодным оружием (4d6, 1 СКОР), которое можно успешно скрыть без проверки." },
            new CyberwareDef { Name = "Контрацептивный имплант", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "0 (—)", Description = "Предотвращает нежелательную беременность." },
            new CyberwareDef { Name = "Назальные фильтры", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "1d6/2 (2)", Description = "У тебя иммунитет к воздействию токсичных газов, паров\r\nи подобных опасностей, которые должны быть втянуты носом. Ты можешь\r\nотключить фильтры по желанию без использования действия." },
            new CyberwareDef { Name = "Независимый запас воздуха", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "1d6/2 (2)", Description = "Содержит запас воздуха на 30 минут. После этого баллон нужно заправить из окружающей\r\nсреды, что занимает час. Замена пустого баллона на полный (50eb) занимает 1 действие." },
            new CyberwareDef { Name = "Радар/сонар-имплант", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "2d6 (7)", Description = "Постоянно сканирует местность в радиусе 50 м на наличие новых угроз,\r\nвключая подводные объекты. Сканирование не видит то, что находится\r\nза укрытием (например, содержимое комнаты за закрытой дверью). Рефери\r\nподает тебе звуковой сигнал и указывает направление, когда обнаруживается\r\nновый движущийся объект. Повторная установка не дает преимуществ." },
            new CyberwareDef { Name = "Связыватели токсинов", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "1d6/2 (2)", Description = "+2 к проверкам сопротивления пыткам/наркотикам.\r\nПовторная установка не дает преимуществ.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Сопр. пыткам/наркотикам", Value = 2 } } },
            new CyberwareDef { Name = "Сексуальный имплант Мистер Перчик", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "2d6 (7)", Description = "Всю ночь, каждую ночь. И никто не узнает." },
            new CyberwareDef { Name = "Сексуальный имплант Полуночница", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "2d6 (7)", Description = "Будь Венерой, будь огнём, будь желанием." },
            new CyberwareDef { Name = "Усиленные антитела", Category = "ВНУТРЕННИЕ ИМПЛАНТЫ (INTERNAL)", Slots = 1, HumanityLoss = "1d6/2 (2)", Description = "После стабилизации ты восстанавливаешь количество ПЗ, равное\r\nтвоему ТЕЛО, умноженному на два, за каждый день отдыха или легкой\r\nактивности. Это заменяет твою обычную скорость исцеления." },

            // ================== ВНЕШНИЕ ИМПЛАНТЫ ==================
            new CyberwareDef { Name = "Плетёная кожа", Category = "ВНЕШНИЕ ИМПЛАНТЫ (EXTERNAL)", Slots = 1, HumanityLoss = "2d6 (7)", Description = "Твое тело и голова защищены броней с показателем ОС7. Твоя ОС в любом месте\r\nопределяется самым высоким источником ОС в этой локации. Кроме того, когда\r\nтвоя броня подвергается разрушению где либо, все твои источники ОС в этом\r\nместе разрушаются одновременно. Всякий раз, когда ты успешно завершаешь день\r\nестественного исцеления, наномашины, присутствующие в Плетёной коже,\r\nвосстанавливают по одному пункту потерянного ОС как тела, так и головы." },
            new CyberwareDef { Name = "Подкожная броня", Category = "ВНЕШНИЕ ИМПЛАНТЫ (EXTERNAL)", Slots = 1, HumanityLoss = "4d6 (14)", Description = "Твое тело и голова защищены броней с показателем ОС11. Твоя ОС в любом\r\nместе определяется самым высоким источником ОС в этом месте. Кроме того,\r\nкогда твоя броня подвергается разрушению где либо, все твои источники\r\nОС в этом месте разрушаются одновременно. Всякий раз, когда ты успешно\r\nзавершаешь день естественного исцеления, наномашины в подкожной броне\r\nвосстанавливают по одному пункту потерянного ОС как тела, так и головы." },
            new CyberwareDef { Name = "Подкожный карман", Category = "ВНЕШНИЕ ИМПЛАНТЫ (EXTERNAL)", Slots = 1, HumanityLoss = "1d6 (3)", Description = "Пространство размером 5 см x 10 см с застежкой-молнией Realskinn™.\r\nСодержимое можно успешно скрыть без проверки." },
            new CyberwareDef { Name = "Скрытая кобура", Category = "ВНЕШНИЕ ИМПЛАНТЫ (EXTERNAL)", Slots = 1, HumanityLoss = "2d6 (7)", Description = "Кобура внутри твоего тела может хранить оружие, которое уже пригодно для скрытого\r\nношения, так что его можно успешно спрятать без броска. Оружие можно достать из скры-\r\nтой кобуры без использования действия, если она имплантирована в легкодоступном месте\r\nна твоем теле. Тебе вряд ли захочется ставить ее в бедро, если ты не носишь штаны." },

            // ================== КИБЕРРУКИ (ПРАВАЯ) ==================
            new CyberwareDef { Name = "Киберрука", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 0, HumanityLoss = "2d6 (7)", IsFoundation = true, Description = "Протез руки. Имеет 4 слота опций. Поставляется со стандартной кистью,\r\nне вызывающей потерю человечности и не занимающей слот." },
            new CyberwareDef { Name = "Стандартная кисть", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 0, HumanityLoss = "1d6/2 (2)", Requires = "Киберрука", Description = "Выглядит как обычная человеческая кисть. Если установлена в биоруку, не считается\r\nв лимит киберимплантов, размещённых в биоконечности.\r\nНе занимает слот опций для киберруки." },
            new CyberwareDef { Name = "Большие костяшки", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Бронированные кастеты. Среднее холодное оружие (2d6\r\nурона, СКОР 2), которое можно скрыть без проверки. При использовании\r\nкак оружие пользователь не может держать что-либо этой рукой. Может\r\nбыть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Быстросъёмное крепление", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 1, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Киберрука может устанавливаться в открытый разъём и сниматься\r\nДействием. При первой установке новой киберруки (через быстросъёмное крепление\r\nили иначе) всегда начисляется потеря человечности. Повторная установка уже\r\nиспользованной руки через быстросъёмное крепление её не вызывает." },
            new CyberwareDef { Name = "Выкидное дальнобойное оружие", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Одноручное дальнобойное оружие (не обязано быть скрываемым\r\nдо установки), предоставленное пользователем, встраивается в киберруку вместе\r\nс установленными на нём приспособлениями для оружия. Можно скрыть без проверки,\r\nизвлекать и убирать без действия. В разложенном состоянии пользователь не может\r\nдержать что-либо этой рукой. Требует киберруку и занимает 2 слота опций." },
            new CyberwareDef { Name = "Выкидное холодное оружие", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Одноручное лёгкое, среднее или тяжёлое холодное оружие (не обязано\r\nбыть скрываемым до установки) встраивается в киберруку. Можно скрыть без броска\r\nи извлекать/убирать без действия. В разложенном состоянии пользователь не может\r\nдержать что-либо этой рукой. Требует киберруку и занимает 2 слота опций." },
            new CyberwareDef { Name = "Выкидной гранатомёт", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Одноручный гранатомёт с одним снарядом, несовмести-\r\nмый со всеми приспособлениями для оружия, кроме интерфейса умного\r\nоружия, встраивается в киберруку. Можно скрыть без проверки, извлекать\r\nи убирать без действия. В разложенном состоянии пользователь не может дер-\r\nжать что-либо этой рукой. Требует киберруку и занимает 2 слота опций." },
            new CyberwareDef { Name = "Выкидной щит", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 3, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Пуленепробиваемый щит складывается внутри киберруки. Можно\r\nизвлекать и убирать без действия, если у щита больше 0 ПЗ. В разложенном состоянии\r\nкиберрука может использоваться только как щит. Пользователь не может держать ничего,\r\nкроме него. Щит легко извлекается для чистки или замены. См. правила использования\r\nщитов в разделе Бой, стр. 183. Требует киберруку и занимает 3 слота опций." },
            new CyberwareDef { Name = "Грейферная рука", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Действием пользователь выстреливает реактивным гарпуном,\r\nкоторый цепляется за толстое укрытие на дистанции до 30 м. Трос выдерживает вес\r\nдо двукратного веса пользователя и имеет 10 ПЗ. Пользователь игнорирует стандартный\r\nштраф за перемещение при лазании и может втянуть трос без действия, в том\r\nчисле во время подъёма. В разложенном состоянии пользователь не может дер-\r\nжать что-либо этой рукой. Неэффективен как оружие и не может\r\nиспользоваться для захвата. Требует киберруку." },
            new CyberwareDef { Name = "Кибердека", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 3, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Кибердека навсегда встраивается в киберруку. Деку\r\nпредоставляет пользователь при установке. Помимо защиты от потери, интеграция\r\nдаёт кибердеке +1 дополнительный слот, который можно использовать\r\nдля программ или железа. Улучшение постоянное. Попытка извлечь деку разрушает\r\nеё без возможности ремонта (программы и железо можно спасти). Требует\r\nкиберруку, интерфейсный разъём и нейролинк и занимает 3 слота опций." },
            new CyberwareDef { Name = "Когти", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 1, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Выдвижные когти из карбостекла. Среднее холодное оружие (2d6\r\nурона, СКОР 2), скрывается без проверки. При использовании как оружие по льзователь\r\nне может держать что-либо этой рукой. Может быть установлен как единственный кибе-\r\nримплант в биоруке. Может быть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Медсканер", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Медсканер, установленный в киберруку. Сканер\r\nс внешними датчиками диагностирует травмы и болезни, позволяя\r\nоказывать неотложную помощь без навыка хирургии. +2 к первой помощи\r\nи парамедицине. Требует киберруку и занимает 2 слота опций.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Первая помощь", Value = 2 }, new SkillModifierDef { SkillName = "Парамедик (x2)", Value = 2 } } },
            new CyberwareDef { Name = "Наплечная камера", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Камера в выдвижном модуле на плече, автономно\r\nотслеживает цель и записывает видео и аудио на щепку памяти\r\nили связанный агент. Можно скрыть без проверки, извлекать и убирать\r\nбез действия. Требует киберруку и занимает 2 слота опций." },
            new CyberwareDef { Name = "Подкожный захват", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Нейроимплант. Подкожная пластина в ладони позволяет\r\nиспользовать умное оружие. Более дешёвая альтернатива интерфейсного разъ-\r\nёма. Может быть установлен как единственный киберимплант в биоруке. Требует\r\nнейролинк и занимает слот опции нейроимпланта. Требует нейролинк." },
            new CyberwareDef { Name = "Потрошители", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Выдвижные когти из карбостекла в костяшках. Тяжё-\r\nлое холодное оружие (3d6 урона, СКОР 2), скрывается без проверки.\r\nПри использовании как оружие пользователь не может держать что-либо этой\r\nрукой. Может быть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Резать и рубить", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Монофиламентный хлыст, встроенный в большой палец.\r\nСреднее холодное оружие (2d6 урона, СКОР 2), скрывается без проверки.\r\nПри использовании как оружие пользователь не может держать что-либо этой\r\nрукой. Может быть установлен как единственный киберимплант в биоруке.\r\nМожет быть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Рука мультитул", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Пальцы содержат отвёртку, гаечный ключ, мини-\r\nдрель и другие инструменты. Ты всегда с инструментом. Может\r\nбыть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Техсканер", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Сканер анализирует технику и электронику, помогая\r\nв ремонте и технической работе. Пользователь получает +2 к навыкам: Основы\r\nтехники, Кибертехника, Автомеханика, Судоремонт, Авиатехника, Электроника/\r\nБезопасность, Оружейная техника. Требует киберруку и занимает 2 слота\r\nопций. Повторная установка не даёт дополнительных преимуществ.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Знание техники", Value = 2 }, new SkillModifierDef { SkillName = "Кибертехника", Value = 2 }, new SkillModifierDef { SkillName = "Автомеханика", Value = 2 }, new SkillModifierDef { SkillName = "Судоремонт", Value = 2 }, new SkillModifierDef { SkillName = "Авиационные технологии", Value = 2 }, new SkillModifierDef { SkillName = "Электроника/Безопасность (x2)", Value = 2 }, new SkillModifierDef { SkillName = "Оружейник", Value = 2 } } },
            new CyberwareDef { Name = "Царапки", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Киберрука", Description = "Ногти из карбостекла с диагональным резом. Лёгкое холодное оружие\r\n(1d6 урона, СКОР 2), скрывается без проверки. При использовании как оружие по льзо-\r\nватель не может держать что-либо этой рукой. Может быть установлен как единственный\r\nкиберимплант в биоруке. Может быть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Закалённое экранирование", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Опция киберконечности. Киберконечность и её установленные опции не выводятся\r\nиз строя эффектами ЭМИ (например, микроволновыми импульсами) или эффектами\r\nпрограмм, не относящихся к Чёрному Льду. Требует киберруку или киберногу." },
            new CyberwareDef { Name = "Пластиковое покрытие", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 0, HumanityLoss = "0 (—)", Requires = "Киберрука", Description = "Опция киберконечности. Пластиковое покрытие. Доступно в широком диапазоне цве-\r\nтов и узоров. Требует киберруку или киберногу, но не занимает слот опций." },
            new CyberwareDef { Name = "Покрытие Realskinn", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 0, HumanityLoss = "0 (—)", Requires = "Киберрука", Description = "Опция киберконечности. Искусственная кожа для киберконечности.\r\nТребует киберруку или киберногу, но не занимает слот опций." },
            new CyberwareDef { Name = "Покрытие Superchrome", Category = "ПРАВАЯ КИБЕРРУКА (CYBERARM R)", Slots = 0, HumanityLoss = "0 (—)", Requires = "Киберрука", Description = "Опция киберконечности. Блестящее металлическое покрытие для киберконечности. +2\r\nк гардеробу и стилю. Требует киберруку или киберногу, но не занимает слот опций.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Гардероб и стиль", Value = 2 } } },

            // ================== КИБЕРРУКИ (ЛЕВАЯ) ==================
            new CyberwareDef { Name = "Киберрука", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 0, HumanityLoss = "2d6 (7)", IsFoundation = true, Description = "Протез руки. Имеет 4 слота опций. Поставляется со стандартной кистью,\r\nне вызывающей потерю человечности и не занимающей слот." },
            new CyberwareDef { Name = "Стандартная кисть", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 0, HumanityLoss = "1d6/2 (2)", Requires = "Киберрука", Description = "Выглядит как обычная человеческая кисть. Если установлена в биоруку, не считается\r\nв лимит киберимплантов, размещённых в биоконечности.\r\nНе занимает слот опций для киберруки." },
            new CyberwareDef { Name = "Большие костяшки", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Бронированные кастеты. Среднее холодное оружие (2d6\r\nурона, СКОР 2), которое можно скрыть без проверки. При использовании\r\nкак оружие пользователь не может держать что-либо этой рукой. Может\r\nбыть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Быстросъёмное крепление", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 1, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Киберрука может устанавливаться в открытый разъём и сниматься\r\nДействием. При первой установке новой киберруки (через быстросъёмное крепление\r\nили иначе) всегда начисляется потеря человечности. Повторная установка уже\r\nиспользованной руки через быстросъёмное крепление её не вызывает." },
            new CyberwareDef { Name = "Выкидное дальнобойное оружие", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Одноручное дальнобойное оружие (не обязано быть скрываемым\r\nдо установки), предоставленное пользователем, встраивается в киберруку вместе\r\nс установленными на нём приспособлениями для оружия. Можно скрыть без проверки,\r\nизвлекать и убирать без действия. В разложенном состоянии пользователь не может\r\nдержать что-либо этой рукой. Требует киберруку и занимает 2 слота опций." },
            new CyberwareDef { Name = "Выкидное холодное оружие", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Одноручное лёгкое, среднее или тяжёлое холодное оружие (не обязано\r\nбыть скрываемым до установки) встраивается в киберруку. Можно скрыть без броска\r\nи извлекать/убирать без действия. В разложенном состоянии пользователь не может\r\nдержать что-либо этой рукой. Требует киберруку и занимает 2 слота опций." },
            new CyberwareDef { Name = "Выкидной гранатомёт", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Одноручный гранатомёт с одним снарядом, несовмести-\r\nмый со всеми приспособлениями для оружия, кроме интерфейса умного\r\nоружия, встраивается в киберруку. Можно скрыть без проверки, извлекать\r\nи убирать без действия. В разложенном состоянии пользователь не может дер-\r\nжать что-либо этой рукой. Требует киберруку и занимает 2 слота опций." },
            new CyberwareDef { Name = "Выкидной щит", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 3, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Пуленепробиваемый щит складывается внутри киберруки. Можно\r\nизвлекать и убирать без действия, если у щита больше 0 ПЗ. В разложенном состоянии\r\nкиберрука может использоваться только как щит. Пользователь не может держать ничего,\r\nкроме него. Щит легко извлекается для чистки или замены. См. правила использования\r\nщитов в разделе Бой, стр. 183. Требует киберруку и занимает 3 слота опций." },
            new CyberwareDef { Name = "Грейферная рука", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Действием пользователь выстреливает реактивным гарпуном,\r\nкоторый цепляется за толстое укрытие на дистанции до 30 м. Трос выдерживает вес\r\nдо двукратного веса пользователя и имеет 10 ПЗ. Пользователь игнорирует стандартный\r\nштраф за перемещение при лазании и может втянуть трос без действия, в том\r\nчисле во время подъёма. В разложенном состоянии пользователь не может дер-\r\nжать что-либо этой рукой. Неэффективен как оружие и не может\r\nиспользоваться для захвата. Требует киберруку." },
            new CyberwareDef { Name = "Кибердека", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 3, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Кибердека навсегда встраивается в киберруку. Деку\r\nпредоставляет пользователь при установке. Помимо защиты от потери, интеграция\r\nдаёт кибердеке +1 дополнительный слот, который можно использовать\r\nдля программ или железа. Улучшение постоянное. Попытка извлечь деку разрушает\r\nеё без возможности ремонта (программы и железо можно спасти). Требует\r\nкиберруку, интерфейсный разъём и нейролинк и занимает 3 слота опций." },
            new CyberwareDef { Name = "Когти", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 1, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Выдвижные когти из карбостекла. Среднее холодное оружие (2d6\r\nурона, СКОР 2), скрывается без проверки. При использовании как оружие по льзователь\r\nне может держать что-либо этой рукой. Может быть установлен как единственный кибе-\r\nримплант в биоруке. Может быть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Медсканер", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Медсканер, установленный в киберруку. Сканер\r\nс внешними датчиками диагностирует травмы и болезни, позволяя\r\nоказывать неотложную помощь без навыка хирургии. +2 к первой помощи\r\nи парамедицине. Требует киберруку и занимает 2 слота опций.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Первая помощь", Value = 2 }, new SkillModifierDef { SkillName = "Парамедик (x2)", Value = 2 } } },
            new CyberwareDef { Name = "Наплечная камера", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Камера в выдвижном модуле на плече, автономно\r\nотслеживает цель и записывает видео и аудио на щепку памяти\r\nили связанный агент. Можно скрыть без проверки, извлекать и убирать\r\nбез действия. Требует киберруку и занимает 2 слота опций." },
            new CyberwareDef { Name = "Подкожный захват", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Нейроимплант. Подкожная пластина в ладони позволяет\r\nиспользовать умное оружие. Более дешёвая альтернатива интерфейсного разъ-\r\nёма. Может быть установлен как единственный киберимплант в биоруке. Требует\r\nнейролинк и занимает слот опции нейроимпланта. Требует нейролинк." },
            new CyberwareDef { Name = "Потрошители", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Выдвижные когти из карбостекла в костяшках. Тяжё-\r\nлое холодное оружие (3d6 урона, СКОР 2), скрывается без проверки.\r\nПри использовании как оружие пользователь не может держать что-либо этой\r\nрукой. Может быть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Резать и рубить", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Монофиламентный хлыст, встроенный в большой палец.\r\nСреднее холодное оружие (2d6 урона, СКОР 2), скрывается без проверки.\r\nПри использовании как оружие пользователь не может держать что-либо этой\r\nрукой. Может быть установлен как единственный киберимплант в биоруке.\r\nМожет быть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Рука мультитул", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Пальцы содержат отвёртку, гаечный ключ, мини-\r\nдрель и другие инструменты. Ты всегда с инструментом. Может\r\nбыть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Техсканер", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 2, HumanityLoss = "2d6 (7)", Requires = "Киберрука", Description = "Сканер анализирует технику и электронику, помогая\r\nв ремонте и технической работе. Пользователь получает +2 к навыкам: Основы\r\nтехники, Кибертехника, Автомеханика, Судоремонт, Авиатехника, Электроника/\r\nБезопасность, Оружейная техника. Требует киберруку и занимает 2 слота\r\nопций. Повторная установка не даёт дополнительных преимуществ.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Знание техники", Value = 2 }, new SkillModifierDef { SkillName = "Кибертехника", Value = 2 }, new SkillModifierDef { SkillName = "Автомеханика", Value = 2 }, new SkillModifierDef { SkillName = "Судоремонт", Value = 2 }, new SkillModifierDef { SkillName = "Авиационные технологии", Value = 2 }, new SkillModifierDef { SkillName = "Электроника/Безопасность (x2)", Value = 2 }, new SkillModifierDef { SkillName = "Оружейник", Value = 2 } } },
            new CyberwareDef { Name = "Царапки", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 1, HumanityLoss = "1d6/2 (2)", Requires = "Киберрука", Description = "Ногти из карбостекла с диагональным резом. Лёгкое холодное оружие\r\n(1d6 урона, СКОР 2), скрывается без проверки. При использовании как оружие по льзо-\r\nватель не может держать что-либо этой рукой. Может быть установлен как единственный\r\nкиберимплант в биоруке. Может быть единственным киберимплантом в мясной руке." },
            new CyberwareDef { Name = "Закалённое экранирование", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Опция киберконечности. Киберконечность и её установленные опции не выводятся\r\nиз строя эффектами ЭМИ (например, микроволновыми импульсами) или эффектами\r\nпрограмм, не относящихся к Чёрному Льду. Требует киберруку или киберногу." },
            new CyberwareDef { Name = "Пластиковое покрытие", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 0, HumanityLoss = "0 (—)", Requires = "Киберрука", Description = "Опция киберконечности. Пластиковое покрытие. Доступно в широком диапазоне цве-\r\nтов и узоров. Требует киберруку или киберногу, но не занимает слот опций." },
            new CyberwareDef { Name = "Покрытие Realskinn", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 0, HumanityLoss = "0 (—)", Requires = "Киберрука", Description = "Опция киберконечности. Искусственная кожа для киберконечности.\r\nТребует киберруку или киберногу, но не занимает слот опций." },
            new CyberwareDef { Name = "Покрытие Superchrome", Category = "ЛЕВАЯ КИБЕРРУКА (CYBERARM L)", Slots = 0, HumanityLoss = "0 (—)", Requires = "Киберрука", Description = "Опция киберконечности. Блестящее металлическое покрытие для киберконечности. +2\r\nк гардеробу и стилю. Требует киберруку или киберногу, но не занимает слот опций.",
                SkillModifiers = new List<SkillModifierDef> { new SkillModifierDef { SkillName = "Гардероб и стиль", Value = 2 } } },

            // ================== КИБЕРНОГИ (ПРАВАЯ) ==================
            new CyberwareDef { Name = "Кибернога", Category = "ПРАВАЯ КИБЕРНОГА (CYBERLEG R)", Slots = 0, HumanityLoss = "1d6 (3)", IsFoundation = true, Description = "Протез ноги. Не требует парной установки. У киберноги есть 3 ячейки для опций кибер-\r\nноги или киберконечности, каждая изначально оснащена стандартной ступнёй, которая\r\nне вызывает Потери Человечности и не занимает ячейку опции киберноги. Большинство\r\nопций киберноги требуют парной установки (покупаются дважды и устанавливаются в две\r\nразные киберноги). Потеря человечности рассчитывается отдельно за каждую покупку." },
            new CyberwareDef { Name = "Стандартная стопа", Category = "ПРАВАЯ КИБЕРНОГА (CYBERLEG R)", Slots = 0, HumanityLoss = "1d6/2 (2)", Requires = "Кибернога", Description = "Выглядит как обычная ступня. При установке в «мясную» ногу не учитывается в общем\r\nколичестве киберимплантов, установленных в неё. Не занимает ячейку опции киберноги." },
            new CyberwareDef { Name = "Когтистая стопа", Category = "ПРАВАЯ КИБЕРНОГА (CYBERLEG R)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Кибернога", Description = "Клинок, установленный в стопе. Лёгкое холодное оружие. Может быть скрыто.\r\nМожет быть установлено как единственный киберимплант в мясной ноге." },
            new CyberwareDef { Name = "Перепончатая стопа", Category = "ПРАВАЯ КИБЕРНОГА (CYBERLEG R)", Slots = 1, IsPaired = true, HumanityLoss = "1d6 (3)", Requires = "Кибернога", Description = "Перепонки между пальцами. Игнорирует штраф\r\nк передвижению при плавании. Требует две сопряжённые киберноги." },
            new CyberwareDef { Name = "Роликовая стопа", Category = "ПРАВАЯ КИБЕРНОГА (CYBERLEG R)", Slots = 1, IsPaired = true, HumanityLoss = "1d6 (3)", Requires = "Кибернога", Description = "Встроенные роликовые коньки. Можно скрыть. При использовании\r\nдействия Бег увеличивает перемещение на 6 м. Требует две сопряжённые киберноги." },
            new CyberwareDef { Name = "Усилитель прыжка", Category = "ПРАВАЯ КИБЕРНОГА (CYBERLEG R)", Slots = 2, IsPaired = true, HumanityLoss = "1d6 (3)", Requires = "Кибернога", Description = "Гидравлика в ногах. Игнорирует штраф к передвижению\r\nпри прыжках. Требует две сопряжённые киберноги, занимает 2 слота опций." },
            new CyberwareDef { Name = "Цепкая стопа", Category = "ПРАВАЯ КИБЕРНОГА (CYBERLEG R)", Slots = 1, IsPaired = true, HumanityLoss = "1d6 (3)", Requires = "Кибернога", Description = "Ступни покрыты современным сцепляющим материалом. Игнорирует\r\nобычный штраф к передвижению при лазании. Требует две сопряжённые киберноги." },
            new CyberwareDef { Name = "Закалённое экранирование", Category = "ПРАВАЯ КИБЕРНОГА (CYBERLEG R)", Slots = 1, HumanityLoss = "1d6 (3)", Requires = "Киберрука", Description = "Опция киберконечности. Киберконечность и её установленные опции не выводятся\r\nиз строя эффектами ЭМИ (например, микроволновыми импульсами) или эффектами\r\nпрограмм, не относящихся к Чёрному Льду. Требует киберруку или киберногу." },
