            new CyberwareDef { Name = "Покрытие Realskinn", Category = "ПРАВАЯ КИБЕРНОГА (CYBERLEG R)", Slots = 0, HumanityLoss = "0 (—)", Requires = "Киберрука", Description = "Опция киберконечности. Искусственная кожа для киберконечности.\r\nТребует киберруку или киберногу, но не занимает слот опций." },
